import random

# Helper function for determining level
def randomized_level(max_level, p):
    lvl = 0
    while random.random() < p and lvl < max_level - 1:
        lvl += 1
    return lvl

class SkipListNode:
    """Represents a node in the skip list."""
    def __init__(self, key=None, value=None, level=0):
        # forward[i] is the pointer at level i
        self.forward = [None] * (level + 1)
        self.key = key
        self.value = value

class SkipList:
    """Probabilistic skip list implementation."""
    def __init__(self, max_level: int = 16, p: float = 0.5):
        self.MAX_LEVEL = max_level
        self.P = p
        # Header node doesn't store data; it points to the start of all levels.
        self.header = SkipListNode(key=float('-inf'), value=None, level=max_level)

        # Current theoretical maximum level actually used in the list
        self.level = 0
        self._size = 0

    def search(self, key):
        current = self.header

        # Start from the highest current level down to level 0
        for i in range(self.level, -1, -1):
            while current.forward[i] and current.forward[i].key < key:
                current = current.forward[i]
            # After the loop, current.forward[i] is either None or points to a node >= key

        # Move one step forward at level 0 (where all elements are)
        candidate = current.forward[0]

        if candidate and candidate.key == key:
            return candidate.value
        else:
            return None

    def insert(self, key, value=None):
        # Find the path to update pointers (update[i] stores the node before target at level i)
        update = [None] * (self.MAX_LEVEL + 1)
        current = self.header

        for i in range(self.level, -1, -1):
            while current.forward[i] and current.forward[i].key < key:
                current = current.forward[i]
            update[i] = current

        # Check for existence (Handle updates)
        if self.search(key) is not None or update[0].forward[0] and update[0].forward[0].key == key:
             # Key exists, update value
            existing_node = update.forward[0]
            if existing_node:
                existing_node.value = value

        else:
            # New node needs insertion
            new_level = randomized_level(self.MAX_LEVEL, self.P)

